/**
 * SAML Relying Party DELETE handler (samlgw2)
 *
 * Deletes RP from samlgw2, removes callback URL from Cognito SAML client,
 * and removes SP info from DynamoDB.
 */

import { DeleteItemCommand, QueryCommand } from '@aws-sdk/client-dynamodb';
import {
  CognitoIdentityProviderClient,
  DescribeUserPoolClientCommand,
  UpdateUserPoolClientCommand,
} from '@aws-sdk/client-cognito-identity-provider';
import {
  createSamlGw2ClientFromEnv,
  buildSamlgw2ItorgId,
} from '../samlgw2-client/index.mjs';

const cognito = new CognitoIdentityProviderClient({ region: process.env.AWS_REGION });

async function getTenantInfo(tenantId, dynamodb, tenantTable) {
  const result = await dynamodb.send(new QueryCommand({
    TableName: tenantTable,
    KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
    ExpressionAttributeValues: {
      ':id': { S: `TENANT#${tenantId}` },
      ':sk_prefix': { S: 'TENANT#' },
    },
  }));
  if (!result.Items || result.Items.length === 0) return null;
  const item = result.Items[0];
  return {
    orgId: item.org_id?.S,
    userPoolId: item.userpool?.S,
    samlClientId: item.samlClientId?.S,
  };
}

async function getSamlgw2ItorgId(tenantOrgId, dynamodb, tenantTable) {
  try {
    const result = await dynamodb.send(new QueryCommand({
      TableName: tenantTable,
      KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
      ExpressionAttributeValues: {
        ':id': { S: `ORG#${tenantOrgId}` },
        ':sk_prefix': { S: 'ORG#' },
      },
      ProjectionExpression: 'samlgw2_itorg_id',
    }));
    const stored = result.Items?.[0]?.samlgw2_itorg_id?.S;
    if (stored) return stored;
  } catch (e) {
    console.log('Failed to query org:', e.message);
  }
  return buildSamlgw2ItorgId(process.env.ACCOUNT_ID, tenantOrgId);
}

/**
 * Remove a callback URL from the Cognito SAML client.
 */
async function removeCallbackUrlFromSamlClient(userPoolId, samlClientId, callbackUrlToRemove) {
  const describeResult = await cognito.send(new DescribeUserPoolClientCommand({
    UserPoolId: userPoolId,
    ClientId: samlClientId,
  }));

  const client = describeResult.UserPoolClient;
  const currentCallbackUrls = client.CallbackURLs || [];

  const updatedCallbackUrls = currentCallbackUrls.filter(url => url !== callbackUrlToRemove);

  // Only update if something changed
  if (updatedCallbackUrls.length === currentCallbackUrls.length) {
    console.log('Callback URL not found in SAML client, skipping');
    return;
  }

  // Cognito requires at least one callback URL
  if (updatedCallbackUrls.length === 0) {
    console.warn('Cannot remove last callback URL from SAML client, keeping it');
    return;
  }

  await cognito.send(new UpdateUserPoolClientCommand({
    UserPoolId: userPoolId,
    ClientId: samlClientId,
    ClientName: client.ClientName,
    RefreshTokenValidity: client.RefreshTokenValidity,
    AccessTokenValidity: client.AccessTokenValidity,
    IdTokenValidity: client.IdTokenValidity,
    TokenValidityUnits: client.TokenValidityUnits,
    ExplicitAuthFlows: client.ExplicitAuthFlows,
    SupportedIdentityProviders: client.SupportedIdentityProviders,
    AllowedOAuthFlows: client.AllowedOAuthFlows,
    AllowedOAuthScopes: client.AllowedOAuthScopes,
    AllowedOAuthFlowsUserPoolClient: client.AllowedOAuthFlowsUserPoolClient,
    CallbackURLs: updatedCallbackUrls,
    LogoutURLs: client.LogoutURLs,
    PreventUserExistenceErrors: client.PreventUserExistenceErrors,
  }));

  console.log(`Removed callback URL from SAML client: ${callbackUrlToRemove}`);
}

export const deleteResData = async (rpName, dynamodb, tenantId, tenantTable, spInfoTable) => {
  if (!rpName) {
    throw new Error('rpName is required');
  }

  // Get tenant info
  const tenantInfo = await getTenantInfo(tenantId, dynamodb, tenantTable);
  if (!tenantInfo?.orgId) {
    throw new Error('Tenant has no org');
  }

  const itorgId = await getSamlgw2ItorgId(tenantInfo.orgId, dynamodb, tenantTable);
  const customerName = tenantId.toLowerCase();

  // 1. Delete RP from samlgw2
  try {
    const samlgw2 = createSamlGw2ClientFromEnv();
    await samlgw2.deleteRelyingParty(itorgId, customerName, rpName.toLowerCase());
    console.log(`RP '${rpName}' deleted from samlgw2`);
  } catch (gw2Error) {
    console.error('samlgw2 delete RP error:', gw2Error.message);
    // Continue with cleanup even if samlgw2 delete fails
  }

  // 2. Remove callback URL from Cognito SAML client
  if (tenantInfo.userPoolId && tenantInfo.samlClientId) {
    const samlgw2 = createSamlGw2ClientFromEnv();
    const callbackUrl = samlgw2.getOidcCallbackUrl(itorgId, customerName, rpName.toLowerCase());

    try {
      await removeCallbackUrlFromSamlClient(
        tenantInfo.userPoolId,
        tenantInfo.samlClientId,
        callbackUrl,
      );
    } catch (cognitoError) {
      console.error('Failed to remove callback URL from Cognito (non-fatal):', cognitoError.message);
    }
  }

  // 3. Delete from DynamoDB SP info table
  try {
    await dynamodb.send(new DeleteItemCommand({
      TableName: spInfoTable,
      Key: { id: { S: `#SAML#${rpName}` } },
    }));
    console.log('SP info deleted from DynamoDB');
  } catch (err) {
    console.log('Error deleting SAML SPINFO item from dynamodb:', err);
  }

  return { id: rpName, deleted: true };
};

export default deleteResData;
